import { useState, useEffect, useMemo, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { Loader2, ArrowLeft, Download, Filter, AlertTriangle, CheckCircle2, ChevronDown, ChevronUp } from 'lucide-react';
import { toPng } from 'html-to-image';
import jsPDF from 'jspdf';

// --- Interfaces ---

interface ViewerProps {
  timetableId?: string;
  onBack?: () => void;
}

interface FetchedSlot {
  id: string;
  day_of_week: number;
  start_time: string;
  end_time: string;
  slot_type: 'Lecture' | 'Tutorial' | 'Practical';
  subject_code: string;
  subject_name: string;
  subject_type: string;
  group_name: string;
  room_name: string;
  professor_name: string;
  isConflict?: boolean;
}

interface TimeColumn {
  label: string;
  start: string;
  end: string;
  isLunch?: boolean;
}

const DAYS = ['MON', 'TUE', 'WED', 'THU', 'FRI'];

export const TimetableViewer: React.FC<ViewerProps> = ({ timetableId, onBack }) => {
  const [loading, setLoading] = useState(true);
  const [timetableName, setTimetableName] = useState('');
  const [allSlots, setAllSlots] = useState<FetchedSlot[]>([]);
  const [selectedTimetableId, setSelectedTimetableId] = useState<string>(timetableId || '');
  const [timetables, setTimetables] = useState<any[]>([]);
  const pdfRef = useRef<HTMLDivElement>(null);

  // --- View State ---
  const [selectedEntity, setSelectedEntity] = useState<string>('All Sections');

  // --- Helpers ---
  const extractVal = (data: any, key: string) => {
    if (!data) return 'N/A';
    if (Array.isArray(data)) return data.length > 0 ? data[0][key] : 'N/A';
    return data[key] || 'N/A';
  };

  const convertTo12Hour = (time24: string) => {
    if (!time24) return '';
    const [hourStr, minute] = time24.split(':');
    let hour = parseInt(hourStr);
    // const suffix = hour >= 12 ? 'PM' : 'AM';
    hour = hour % 12 || 12; // Convert 0 to 12
    return `${hour}:${minute}`;
  };
  // 1. Fetch Timetables
  useEffect(() => {
    const fetchTTs = async () => {
      const { data } = await supabase.from('timetables').select('id, name, semester').order('created_at', { ascending: false });
      if (data) {
        setTimetables(data);
        if (!selectedTimetableId && data.length > 0) setSelectedTimetableId(data[0].id);
      }
      // If no timetables exist, stop the loading spinner
      if (!data || data.length === 0) setLoading(false);
    };
    fetchTTs();
  }, [selectedTimetableId]);

  // 2. Fetch Slots
  useEffect(() => {
    if (!selectedTimetableId) return;
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setLoading(true);

    const fetchData = async () => {
      const { data: tt } = await supabase.from('timetables').select('name').eq('id', selectedTimetableId).single();
      if (tt) setTimetableName(tt.name);

      const { data, error } = await supabase
        .from('timetable_slots')
        .select(`
          id, day_of_week, start_time, end_time, slot_type,
          subjects (code, name, subject_type), professors (name), rooms (name), student_groups (name)
        `)
        .eq('timetable_id', selectedTimetableId);

      if (error) { setLoading(false); return; }

      const rawData = data as any[];
      const cleanSlots: FetchedSlot[] = rawData.map(s => ({
        id: s.id,
        day_of_week: s.day_of_week,
        start_time: s.start_time,
        end_time: s.end_time,
        slot_type: s.slot_type,
        subject_code: extractVal(s.subjects, 'code'),
        subject_name: extractVal(s.subjects, 'name'),
        subject_type: extractVal(s.subjects, 'subject_type'),
        professor_name: extractVal(s.professors, 'name'),
        room_name: extractVal(s.rooms, 'name'),
        group_name: extractVal(s.student_groups, 'name').replace('Sec', '').trim()
      }));

      setAllSlots(cleanSlots);
      setLoading(false);
    };
    fetchData();
  }, [selectedTimetableId]);

  // 3. Derived Lists
  const allSections = useMemo(() => Array.from(new Set(allSlots.map(s => s.group_name))).sort(), [allSlots]);

  const dropdownOptions = useMemo(() => {
    const unique = new Set(['All Sections', ...allSections]);
    return Array.from(unique);
  }, [allSections]);

  if (dropdownOptions.length > 0 && !dropdownOptions.includes(selectedEntity)) {
    setSelectedEntity(dropdownOptions[0]);
  }

  // --- 4. DYNAMIC COLUMNS ---
  const dynamicTimeColumns = useMemo(() => {
    if (allSlots.length === 0) return [
      { label: '09:00-10:00', start: '09:00', end: '10:00' },
      { label: 'LUNCH', start: '13:00', end: '14:30', isLunch: true }
    ];

    const boundaries = new Set<string>();
    allSlots.forEach(s => {
      boundaries.add(s.start_time.slice(0, 5));
      boundaries.add(s.end_time.slice(0, 5));
    });

    boundaries.add('10:50');
    boundaries.add('11:00');
    boundaries.add('13:00');
    boundaries.add('14:30');

    const sortedTimes = Array.from(boundaries).sort();

    const filteredTimes = sortedTimes.filter(t => {
      if (t > '13:00' && t < '14:30') return false;
      return true;
    });

    const cols: TimeColumn[] = [];
    for (let i = 0; i < filteredTimes.length - 1; i++) {
      const start = filteredTimes[i];
      const end = filteredTimes[i + 1];

      const isLunch = (start === '13:00' && end === '14:30');
      const isBreak = (start === '10:50' && end === '11:00');

      const cStart = parseInt(start.replace(':', ''));
      const cEnd = parseInt(end.replace(':', ''));

      const hasClass = allSlots.some(s => {
        const sStart = parseInt(s.start_time.slice(0, 5).replace(':', ''));
        const sEnd = parseInt(s.end_time.slice(0, 5).replace(':', ''));
        return (sStart < cEnd && sEnd > cStart);
      });

      if (isLunch || isBreak || hasClass) {
        cols.push({
          // 3. SET LABEL
          label: isLunch ? 'LUNCH' : isBreak ? 'BREAK' : `${convertTo12Hour(start)} - ${convertTo12Hour(end)}`,
          start: start,
          end: end,
          // Reuse isLunch flag for styling (gray background) OR add a new one
          isLunch: isLunch || isBreak
        });
      }
    }

    return cols;
  }, [allSlots]);

  // 5. Smart Processing
  const processedSlots = useMemo(() => {
    const uniqueSlots: FetchedSlot[] = [];
    const seenMap = new Map<string, boolean>();

    allSlots.forEach(slot => {
      const dedupKey = `${slot.day_of_week}-${slot.start_time}-${slot.group_name}-${slot.subject_code}`;
      if (!seenMap.has(dedupKey)) {
        seenMap.set(dedupKey, true);
        uniqueSlots.push(slot);
      }
    });

    return uniqueSlots;
  }, [allSlots]);

  // --- Clash Detection ---
  const [showClashDetails, setShowClashDetails] = useState(false);

  interface Clash {
    type: 'Room' | 'Professor' | 'Section' | 'WMC-Section';
    entity: string;
    day: string;
    time: string;
    slots: { code: string; group: string }[];
  }

  const clashes = useMemo(() => {
    if (allSlots.length === 0) return [];

    const timeOverlaps = (s1: FetchedSlot, s2: FetchedSlot) => {
      return s1.start_time < s2.end_time && s2.start_time < s1.end_time;
    };

    const dayNames = ['', 'MON', 'TUE', 'WED', 'THU', 'FRI'];
    const found: Clash[] = [];

    // Check all pairs for same-day overlaps
    for (let i = 0; i < allSlots.length; i++) {
      for (let j = i + 1; j < allSlots.length; j++) {
        const a = allSlots[i], b = allSlots[j];
        if (a.day_of_week !== b.day_of_week) continue;
        if (!timeOverlaps(a, b)) continue;

        const day = dayNames[a.day_of_week] || `Day${a.day_of_week}`;
        const time = `${a.start_time.slice(0, 5)}`;

        // Room clash
        if (a.room_name === b.room_name && a.room_name !== 'N/A') {
          found.push({
            type: 'Room', entity: a.room_name, day, time,
            slots: [
              { code: a.subject_code, group: a.group_name },
              { code: b.subject_code, group: b.group_name },
            ],
          });
        }

        // Professor clash
        if (a.professor_name === b.professor_name && a.professor_name !== 'N/A' && a.professor_name !== 'Unknown' && a.professor_name !== 'TBD') {
          found.push({
            type: 'Professor', entity: a.professor_name, day, time,
            slots: [
              { code: a.subject_code, group: a.group_name },
              { code: b.subject_code, group: b.group_name },
            ],
          });
        }

        const bothElectives = (a.subject_type === 'Elective' || a.subject_type === 'Minor') &&
          (b.subject_type === 'Elective' || b.subject_type === 'Minor');

        // Section clash (same group, different subjects)
        if (a.group_name === b.group_name && a.subject_code !== b.subject_code) {
          if (!bothElectives) {
            found.push({
              type: 'Section', entity: a.group_name, day, time,
              slots: [
                { code: a.subject_code, group: a.group_name },
                { code: b.subject_code, group: b.group_name },
              ],
            });
          }
        }

        // WMC-Section clash: WMC session overlaps with a section session
        const aIsWMC = a.group_name === 'WMC' || a.group_name === 'IT-BI';
        const bIsWMC = b.group_name === 'WMC' || b.group_name === 'IT-BI';
        if (aIsWMC !== bIsWMC) {
          // One is WMC, the other is a section → clash
          if (!bothElectives) {
            found.push({
              type: 'WMC-Section', entity: aIsWMC ? b.group_name : a.group_name, day, time,
              slots: [
                { code: a.subject_code, group: a.group_name },
                { code: b.subject_code, group: b.group_name },
              ],
            });
          }
        }
      }
    }

    return found;
  }, [allSlots]);

  const clashSummary = useMemo(() => {
    const room = clashes.filter(c => c.type === 'Room').length;
    const professor = clashes.filter(c => c.type === 'Professor').length;
    const section = clashes.filter(c => c.type === 'Section').length;
    const wmcSection = clashes.filter(c => c.type === 'WMC-Section').length;
    return { room, professor, section, wmcSection, total: room + professor + section + wmcSection };
  }, [clashes]);

  // --- Render Slot (NO TOOLTIP, ALL INFO ON CARD) ---
  // --- Render Slot (With Initials) ---
  // --- Render Slot (Full Names on Separate Lines) ---
  const renderSlotItem = (slot: FetchedSlot) => {
    const isLab = slot.slot_type === 'Practical';
    const isTutorial = slot.slot_type === 'Tutorial';

    const textColor = isLab ? 'text-orange-600' : isTutorial ? 'text-green-800' : 'text-black';
    const borderColor = 'border-gray-100';

    // 1. Split names by '&' to create an array
    const profNames = slot.professor_name !== 'Unknown'
      ? slot.professor_name.split('&').map(n => n.trim())
      : [];

    return (
      <div key={slot.id} className={`w-full flex flex-col justify-center items-center text-[9px] leading-tight border-b ${borderColor} last:border-0 p-1 ${textColor} bg-transparent`}>
        {/* Line 1: Code & Type */}
        <div className="font-bold whitespace-nowrap">
          {slot.subject_code} ({slot.slot_type.charAt(0)})
        </div>

        {/* Line 2: Professor Names (Stacked) */}
        {profNames.length > 0 && (
          <div className="flex flex-col items-center gap-0 my-0.5">
            {profNames.map((name, idx) => (
              <div key={idx} className="text-[8px] font-bold text-indigo-600 tracking-wide whitespace-nowrap">
                {name}
              </div>
            ))}
          </div>
        )}

        {/* Line 3: Room, Group, and Semester */}
        <div className="scale-90 opacity-90 whitespace-nowrap flex flex-wrap justify-center gap-1 items-center text-black">
          <span className="text-gray-600">{slot.room_name}</span>
          <span className="text-gray-300">•</span>
          <span className="font-semibold text-cyan-800">{slot.group_name}</span>
          {/* <span className="text-gray-300">•</span>
                <span className="text-gray-500 font-medium">Sem {slot.semester}</span> */}
        </div>
      </div>
    );
  };

  // --- Render Cell ---
  const renderCellContent = (dayIndex: number, column: TimeColumn) => {
    const colStart = parseInt(column.start.replace(':', ''));
    const colEnd = parseInt(column.end.replace(':', ''));

    let cellSlots = processedSlots.filter(s => {
      if (s.day_of_week !== dayIndex + 1) return false;
      const slotStart = parseInt(s.start_time.slice(0, 5).replace(':', ''));
      const slotEnd = parseInt(s.end_time.slice(0, 5).replace(':', ''));
      return (slotStart <= colStart && slotEnd >= colEnd);
    });

    if (selectedEntity !== 'All Sections') {
      cellSlots = cellSlots.filter(s =>
        s.group_name === selectedEntity ||
        s.group_name === 'WMC' ||
        s.group_name === 'all'
      );
    }

    if (cellSlots.length === 0) return null;
    // 2. CHECK IF CROWDED (More than 1 slot?)
    // If we have multiple slots (like electives), use a 2-column grid.
    // If it's just 1 slot, keep it simple.
    const isCrowded = cellSlots.length > 4;

    return (
      <div className="h-full flex flex-col justify-start overflow-y-auto custom-scrollbar">
        <div className={isCrowded ? "grid grid-cols-2 gap-1" : "flex flex-col gap-1"}>
          {cellSlots.map(slot => renderSlotItem(slot))}
        </div>
      </div>
    );
  };

  // --- PDF Download (Fixed) ---
  const handleDownloadPDF = async () => {
    if (!pdfRef.current) return;

    try {
      const element = pdfRef.current;
      const width = element.scrollWidth;
      const height = element.scrollHeight;

      // 1. Generate Image (Capturing hidden overflow)
      const imgData = await toPng(element, {
        cacheBust: true,
        backgroundColor: '#ffffff',
        width: width,
        height: height,
        style: {
          overflow: 'visible',
          maxHeight: 'none',
          maxWidth: 'none',
        }
      });

      // 2. Create Dynamic PDF
      const pxToMm = 0.264583;
      const pdfWidth = width * pxToMm;
      const pdfHeight = height * pxToMm;

      const pdf = new jsPDF({
        orientation: pdfWidth > pdfHeight ? 'l' : 'p',
        unit: 'mm',
        format: [pdfWidth + 10, pdfHeight + 10]
      });

      pdf.addImage(imgData, 'PNG', 5, 5, pdfWidth, pdfHeight);
      pdf.save(`timetable-${selectedEntity}.pdf`);

    } catch (err) {
      console.error('PDF Export failed:', err);
      alert('Could not generate PDF. Please check the console.');
    }
  };


  if (loading) return <div className="p-10 flex justify-center"><Loader2 className="animate-spin w-8 h-8 text-indigo-600" /></div>;

  if (timetables.length === 0) {
    return (
      <div className="p-4 bg-gray-50 min-h-screen font-sans flex flex-col items-center justify-center">
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-10 text-center max-w-md">
          <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <Filter className="w-8 h-8 text-gray-300" />
          </div>
          <h2 className="text-lg font-bold text-gray-700 mb-2">No Timetables Available</h2>
          <p className="text-sm text-gray-500">
            There are no timetables in the database yet. Generate one from the <b>Generator</b> tab or import one from the <b>Import</b> tab to view it here.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="p-4 bg-gray-50 min-h-screen font-sans">
      <div className="mb-6 bg-white p-4 rounded-lg shadow-sm border flex flex-col md:flex-row justify-between items-center gap-4 sticky top-0 z-20">
        <div className="flex items-center gap-3">
          {onBack && <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full"><ArrowLeft className="w-5 h-5" /></button>}
          <div>
            <h1 className="text-xl font-bold text-gray-800">{timetableName}</h1>
            <div className="text-xs text-gray-500">
              Sem {timetables.find(t => t.id === selectedTimetableId)?.semester} • {allSections.length} Sections
            </div>
          </div>
        </div>
        <div className="flex flex-wrap gap-2 items-center">
          <select value={selectedTimetableId} onChange={(e) => setSelectedTimetableId(e.target.value)} className="border p-2 rounded text-sm bg-gray-50 shadow-sm outline-none focus:ring-2 focus:ring-indigo-500">
            {timetables.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
          </select>
          <div className="flex items-center gap-1 border p-1 rounded bg-indigo-50 border-indigo-200">
            <Filter className="w-3 h-3 text-indigo-500 ml-1" />
            <select value={selectedEntity} onChange={(e) => setSelectedEntity(e.target.value)} className="bg-transparent text-sm font-semibold text-indigo-900 outline-none min-w-[120px]">
              {dropdownOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}
            </select>
          </div>
          <button onClick={handleDownloadPDF} className="flex items-center gap-2 px-3 py-2 bg-gray-900 text-white text-sm rounded hover:bg-black transition shadow-sm">
            <Download className="w-3.5 h-3.5" /> PDF
          </button>
        </div>
      </div>

      {/* Clash Detection Banner */}
      {allSlots.length > 0 && (
        <div className={`mb-3 rounded-lg border shadow-sm ${clashSummary.total === 0 ? 'bg-green-50 border-green-200' : 'bg-red-50 border-red-200'}`}>
          <button
            onClick={() => setShowClashDetails(prev => !prev)}
            className="w-full px-4 py-2.5 flex items-center justify-between text-sm"
          >
            <div className="flex items-center gap-2">
              {clashSummary.total === 0
                ? <><CheckCircle2 className="w-4 h-4 text-green-600" /><span className="font-semibold text-green-800">No Clashes Detected ✅</span></>
                : <><AlertTriangle className="w-4 h-4 text-red-600" /><span className="font-semibold text-red-800">{clashSummary.total} Clash{clashSummary.total > 1 ? 'es' : ''} Detected</span></>
              }
              {clashSummary.total > 0 && (
                <div className="flex gap-2 ml-3 text-xs">
                  {clashSummary.room > 0 && <span className="bg-red-100 text-red-700 px-2 py-0.5 rounded-full font-medium">Room: {clashSummary.room}</span>}
                  {clashSummary.professor > 0 && <span className="bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full font-medium">Professor: {clashSummary.professor}</span>}
                  {clashSummary.section > 0 && <span className="bg-purple-100 text-purple-700 px-2 py-0.5 rounded-full font-medium">Section: {clashSummary.section}</span>}
                  {clashSummary.wmcSection > 0 && <span className="bg-teal-100 text-teal-700 px-2 py-0.5 rounded-full font-medium">WMC-Section: {clashSummary.wmcSection}</span>}
                </div>
              )}
            </div>
            {clashSummary.total > 0 && (showClashDetails ? <ChevronUp className="w-4 h-4 text-gray-500" /> : <ChevronDown className="w-4 h-4 text-gray-500" />)}
          </button>

          {showClashDetails && clashes.length > 0 && (
            <div className="border-t border-red-200 px-4 py-3 max-h-60 overflow-y-auto">
              <div className="space-y-1.5">
                {clashes.map((clash, i) => (
                  <div key={i} className="flex items-center gap-2 text-xs bg-white px-3 py-1.5 rounded border border-gray-100">
                    <span className={`font-bold px-1.5 py-0.5 rounded text-[10px] ${clash.type === 'Room' ? 'bg-red-100 text-red-700' :
                      clash.type === 'Professor' ? 'bg-orange-100 text-orange-700' :
                        clash.type === 'WMC-Section' ? 'bg-teal-100 text-teal-700' :
                          'bg-purple-100 text-purple-700'
                      }`}>{clash.type}</span>
                    <span className="font-semibold text-gray-700">{clash.entity}</span>
                    <span className="text-gray-400">•</span>
                    <span className="text-gray-500">{clash.day} @ {clash.time}</span>
                    <span className="text-gray-400">→</span>
                    <span className="text-gray-700">
                      {clash.slots.map(s => `${s.code} (${s.group})`).join(' vs ')}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      <div className="overflow-x-auto bg-white p-1 shadow-lg border border-gray-300 rounded-sm">
        <div ref={pdfRef} className="min-w-max">
          <table className="w-full border-collapse border border-black text-center text-xs">
            <thead>
              <tr className="bg-[#e6b8af] h-10">
                <th className="border border-black w-14 shadow-sm">Day</th>
                {dynamicTimeColumns.map((col, idx) => (
                  <th key={idx} className={`border border-black p-1 ${col.isLunch ? 'w-8 bg-gray-200' : ''}`}>
                    {col.isLunch ? <span className="writing-mode-vertical text-[9px] tracking-widest text-gray-600">{col.label}</span> : col.label}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {DAYS.map((day, dayIndex) => (
                <tr key={day} className="border-b border-black bg-white h-65">
                  <td className="border border-black bg-[#e6b8af] font-bold text-sm writing-mode-vertical md:writing-mode-horizontal">
                    {day}
                  </td>
                  {dynamicTimeColumns.map((col, cIdx) => {
                    if (col.isLunch) return <td key={cIdx} className="border border-black bg-gray-100 font-bold writing-mode-vertical text-[10px] tracking-widest text-gray-500 select-none">{col.label}</td>;
                    return (
                      <td key={cIdx} className="border border-black p-0 hover:bg-blue-50/10 transition-colors align-top h-65">
                        {renderCellContent(dayIndex, col)}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <style>{`
        .writing-mode-vertical { writing-mode: vertical-rl; transform: rotate(180deg); }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #f1f1f1; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #ccc; border-radius: 2px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #999; }
      `}</style>
    </div>
  );
};

export default TimetableViewer;

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '../lib/supabase';
import type { EditorSlot } from '../solver/localSearch';

// ─── Types ─────────────────────────────────────────────────────────────────────

export interface TimetableMeta {
    id: string;
    name: string;
    semester: number;
    status: string;
    academic_year: string;
    created_at: string;
    published_at: string | null;
    lunch_start: string;
    lunch_end: string;
}

export interface EditorData {
    // Timetable list
    timetables: TimetableMeta[];
    loadingList: boolean;

    // Current timetable
    selectedTimetableId: string;
    setSelectedTimetableId: (id: string) => void;
    timetableMeta: TimetableMeta | null;

    // Slots
    slots: EditorSlot[];
    setSlots: React.Dispatch<React.SetStateAction<EditorSlot[]>>;
    loadingSlots: boolean;

    // Rooms & professors for editing
    rooms: { id: string; name: string; room_type: string }[];
    professors: { id: string; name: string }[];

    // Save & publish
    saveSlots: (slots: EditorSlot[]) => Promise<void>;
    publishTimetable: () => Promise<void>;
    saving: boolean;
    publishing: boolean;

    // Re-fetch
    refresh: () => void;
    error: string | null;
}

// ─── Hook ──────────────────────────────────────────────────────────────────────

export function useEditorData(initialTimetableId?: string): EditorData {
    const [timetables, setTimetables] = useState<TimetableMeta[]>([]);
    const [loadingList, setLoadingList] = useState(true);

    const [selectedTimetableId, setSelectedTimetableId] = useState(initialTimetableId ?? '');
    const [timetableMeta, setTimetableMeta] = useState<TimetableMeta | null>(null);

    const [slots, setSlots] = useState<EditorSlot[]>([]);
    const [loadingSlots, setLoadingSlots] = useState(false);

    const [rooms, setRooms] = useState<{ id: string; name: string; room_type: string }[]>([]);
    const [professors, setProfessors] = useState<{ id: string; name: string }[]>([]);

    const [saving, setSaving] = useState(false);
    const [publishing, setPublishing] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const [refreshKey, setRefreshKey] = useState(0);
    const refresh = useCallback(() => setRefreshKey(k => k + 1), []);

    // Sync external initial ID
    useEffect(() => {
        if (initialTimetableId) setSelectedTimetableId(initialTimetableId);
    }, [initialTimetableId]);

    // ── 1. Load timetable list + rooms + professors ──
    useEffect(() => {
        let cancelled = false;
        async function load() {
            setLoadingList(true);
            setError(null);
            try {
                const [ttRes, roomRes, profRes] = await Promise.all([
                    supabase
                        .from('timetables')
                        .select('id, name, semester, status, academic_year, created_at, published_at, lunch_start, lunch_end')
                        .order('created_at', { ascending: false }),
                    supabase.from('rooms').select('id, name, room_type').order('name'),
                    supabase.from('professors').select('id, name').order('name'),
                ]);
                if (ttRes.error) throw ttRes.error;
                if (roomRes.error) throw roomRes.error;
                if (profRes.error) throw profRes.error;
                if (!cancelled) {
                    setTimetables(ttRes.data ?? []);
                    setRooms(roomRes.data ?? []);
                    setProfessors(profRes.data ?? []);
                }
            } catch (err) {
                if (!cancelled) setError(err instanceof Error ? err.message : 'Failed to load timetables');
            } finally {
                if (!cancelled) setLoadingList(false);
            }
        }
        load();
        return () => { cancelled = true; };
    }, [refreshKey]);

    // ── 2. Load slots for selected timetable ──
    useEffect(() => {
        if (!selectedTimetableId) {
            setSlots([]);
            setTimetableMeta(null);
            return;
        }

        let cancelled = false;
        async function loadSlots() {
            setLoadingSlots(true);
            setError(null);
            try {
                // Load meta
                const meta = timetables.find(t => t.id === selectedTimetableId) ?? null;
                if (!cancelled) setTimetableMeta(meta);

                // Load slots with joined names
                const { data, error: slotErr } = await supabase
                    .from('timetable_slots')
                    .select(`
            id,
            timetable_id,
            subject_id,
            professor_id,
            room_id,
            student_group_id,
            day_of_week,
            start_time,
            end_time,
            slot_type,
            subject:subject_id (code, name, subject_type),
            professor:professor_id (name),
            room:room_id (name),
            student_group:student_group_id (name)
          `)
                    .eq('timetable_id', selectedTimetableId)
                    .order('day_of_week')
                    .order('start_time');

                if (slotErr) throw slotErr;
                if (cancelled) return;

                // Flatten joined data
                const mapped: EditorSlot[] = (data ?? []).map((row: any) => ({
                    id: row.id,
                    timetable_id: row.timetable_id,
                    subject_id: row.subject_id,
                    professor_id: row.professor_id,
                    room_id: row.room_id,
                    student_group_id: row.student_group_id,
                    day_of_week: row.day_of_week,
                    start_time: row.start_time,
                    end_time: row.end_time,
                    slot_type: row.slot_type,
                    subject_code: row.subject?.code ?? '??',
                    subject_name: row.subject?.name ?? 'Unknown',
                    subject_type: row.subject?.subject_type ?? 'Core',
                    professor_name: row.professor?.name ?? 'TBD',
                    room_name: row.room?.name ?? '—',
                    group_name: row.student_group?.name ?? '??',
                }));

                setSlots(mapped);
            } catch (err) {
                if (!cancelled) setError(err instanceof Error ? err.message : 'Failed to load slots');
            } finally {
                if (!cancelled) setLoadingSlots(false);
            }
        }
        loadSlots();
        return () => { cancelled = true; };
    }, [selectedTimetableId, timetables]);

    // ── 3. Save edited slots back to DB ──
    const saveSlots = useCallback(async (editedSlots: EditorSlot[]) => {
        if (!selectedTimetableId) return;
        setSaving(true);
        setError(null);
        try {
            // Delete existing slots for this timetable and re-insert
            const { error: delErr } = await supabase
                .from('timetable_slots')
                .delete()
                .eq('timetable_id', selectedTimetableId);
            if (delErr) throw delErr;

            const rows = editedSlots.map(s => ({
                timetable_id: s.timetable_id,
                subject_id: s.subject_id,
                professor_id: s.professor_id,
                room_id: s.room_id,
                student_group_id: s.student_group_id,
                day_of_week: s.day_of_week,
                start_time: s.start_time,
                end_time: s.end_time,
                slot_type: s.slot_type,
            }));

            const { error: insErr } = await supabase
                .from('timetable_slots')
                .insert(rows);
            if (insErr) throw insErr;
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to save');
            throw err;
        } finally {
            setSaving(false);
        }
    }, [selectedTimetableId]);

    // ── 4. Publish timetable ──
    const publishTimetable = useCallback(async () => {
        if (!selectedTimetableId) return;
        setPublishing(true);
        setError(null);
        try {
            const { error: pubErr } = await supabase
                .from('timetables')
                .update({ status: 'published', published_at: new Date().toISOString() })
                .eq('id', selectedTimetableId);
            if (pubErr) throw pubErr;

            // Update local state
            setTimetableMeta(prev => prev ? { ...prev, status: 'published', published_at: new Date().toISOString() } : null);
            setTimetables(prev => prev.map(t =>
                t.id === selectedTimetableId
                    ? { ...t, status: 'published', published_at: new Date().toISOString() }
                    : t
            ));
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to publish');
            throw err;
        } finally {
            setPublishing(false);
        }
    }, [selectedTimetableId]);

    return {
        timetables,
        loadingList,
        selectedTimetableId,
        setSelectedTimetableId,
        timetableMeta,
        slots,
        setSlots,
        loadingSlots,
        rooms,
        professors,
        saveSlots,
        publishTimetable,
        saving,
        publishing,
        refresh,
        error,
    };
}

import { useState } from 'react';
import toast from 'react-hot-toast';

const SCOPES = 'https://www.googleapis.com/auth/spreadsheets';
const CLIENT_ID = import.meta.env.VITE_GOOGLE_SHEETS_CLIENT_ID;

if (!CLIENT_ID) {
  console.error("Missing Google Client ID. Check your .env file.");
}

export interface SheetData {
  title: string;
  rows: string[][];
}

export function useGoogleSheets() {
  const [isExporting, setIsExporting] = useState(false);

  // --- Helper: Create Workbook & Apply Styling ---
  const createWorkbook = async (accessToken: string, filename: string, sheetsData: SheetData[]) => {
    
    // 1. Define the Pink Color (Matches #e6b8af)
    const pinkColor = { red: 0.9, green: 0.72, blue: 0.69 };

    // 2. Prepare Sheet Configuration (Tabs)
    const sheetsConfig = sheetsData.map(s => ({
      properties: { title: s.title }
    }));

    // 3. Create the Spreadsheet with all Tabs
    const createRes = await fetch('https://sheets.googleapis.com/v4/spreadsheets', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        properties: { title: filename },
        sheets: sheetsConfig
      }),
    });

    if (!createRes.ok) throw new Error('Failed to create spreadsheet');
    const spreadsheetData = await createRes.json();
    const spreadsheetId = spreadsheetData.spreadsheetId;
    
    // 4. Map Titles to Sheet IDs (Google assigns random IDs, we need to track them)
    const sheetIdsMap = spreadsheetData.sheets.reduce((acc: any, s: any) => {
      acc[s.properties.title] = s.properties.sheetId;
      return acc;
    }, {});

    // 5. Prepare Data Payload (Bulk Upload)
    const dataPayload = sheetsData.map(sheet => ({
      range: `${sheet.title}!A1`, 
      values: sheet.rows
    }));

    await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}/values:batchUpdate`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        valueInputOption: 'USER_ENTERED',
        data: dataPayload
      }),
    });

    // 6. Prepare Formatting Payload (Bulk Styling)
    const requests: any[] = [];

    sheetsData.forEach(sheet => {
      const sheetId = sheetIdsMap[sheet.title];
      const rowCount = sheet.rows.length;
      const colCount = sheet.rows[0].length;

      requests.push(
        // A. Global Cell Style (Borders, Center, Wrap)
        {
          repeatCell: {
            range: { sheetId, startRowIndex: 0, endRowIndex: rowCount, startColumnIndex: 0, endColumnIndex: colCount },
            cell: {
              userEnteredFormat: {
                wrapStrategy: "WRAP", verticalAlignment: "MIDDLE", horizontalAlignment: "CENTER",
                borders: { top: { style: "SOLID" }, bottom: { style: "SOLID" }, left: { style: "SOLID" }, right: { style: "SOLID" } }
              }
            },
            fields: "userEnteredFormat(wrapStrategy,verticalAlignment,horizontalAlignment,borders)"
          }
        },
        // B. Header Row Style (Pink & Bold)
        {
          repeatCell: {
            range: { sheetId, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: colCount },
            cell: { userEnteredFormat: { backgroundColor: pinkColor, horizontalAlignment: "CENTER", textFormat: { bold: true, fontSize: 11 } } },
            fields: "userEnteredFormat(backgroundColor,textFormat,horizontalAlignment)"
          }
        },
        // C. First Column Style (Pink & Bold)
        {
          repeatCell: {
            range: { sheetId, startRowIndex: 1, endRowIndex: rowCount, startColumnIndex: 0, endColumnIndex: 1 },
            cell: { userEnteredFormat: { backgroundColor: pinkColor, horizontalAlignment: "CENTER", textFormat: { bold: true } } },
            fields: "userEnteredFormat(backgroundColor,textFormat,horizontalAlignment)"
          }
        },
        // D. Auto-Resize Columns
        { autoResizeDimensions: { dimensions: { sheetId, dimension: "COLUMNS", startIndex: 0, endIndex: colCount } } },
        // E. Freeze Header & First Column
        { updateSheetProperties: { properties: { sheetId, gridProperties: { frozenRowCount: 1, frozenColumnCount: 1 } }, fields: "gridProperties(frozenRowCount,frozenColumnCount)" } }
      );
    });

    // 7. Execute Formatting
    await fetch(`https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}:batchUpdate`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ requests }),
    });

    return spreadsheetData.spreadsheetUrl;
  };

  // --- Main Trigger Function ---
  const exportToWorkbook = (filename: string, sheetsData: SheetData[]) => {
    setIsExporting(true);
    const toastId = toast.loading('Waiting for Google Sign-in...');

    // @ts-ignore
    const client = google.accounts.oauth2.initTokenClient({
      client_id: CLIENT_ID,
      scope: SCOPES,
      callback: async (tokenResponse: any) => {
        if (tokenResponse.access_token) {
          try {
            toast.loading(`Creating ${sheetsData.length} sheets...`, { id: toastId });
            const url = await createWorkbook(tokenResponse.access_token, filename, sheetsData);
            
            toast.success('Workbook created!', { id: toastId });
            window.open(url, '_blank');
          } catch (err) {
            console.error('Export failed:', err);
            toast.error('Failed to create sheet.', { id: toastId });
          } finally {
            setIsExporting(false);
          }
        } else {
            toast.dismiss(toastId);
            setIsExporting(false);
        }
      },
    });

    client.requestAccessToken();
  };

  return { exportToWorkbook, isExporting };
}

import type { SolverInput, SolverResult, ClassSession, Gene } from './types';
import { SLOT_START_TIMES, SLOT_END_TIMES } from './constants';

const DAY_NAMES = ['MON', 'TUE', 'WED', 'THU', 'FRI'];

// ─── Helpers ────────────────────────────────────────────────────────────────────

function slotTime(bucket: number): string {
    return SLOT_START_TIMES[bucket - 1] ?? `slot${bucket}`;
}

function slotEndTime(bucket: number): string {
    return SLOT_END_TIMES[bucket - 1] ?? `slot${bucket}`;
}

function dayName(day: number): string {
    return DAY_NAMES[day - 1] ?? `Day${day}`;
}

function sessionLabel(s: ClassSession): string {
    return `[#${s.id}] ${s.subjectCode} (${s.slotType}${s.duration > 1 ? ` ×${s.duration}hr` : ''})${s.isLocked ? ' 🔒' : ''}`;
}

function geneLabel(g: Gene, s: ClassSession, rooms: SolverInput['rooms']): string {
    const room = rooms[g.roomIndex];
    const endBucket = g.startBucket + s.duration - 1;
    return `${dayName(g.day)} ${slotTime(g.startBucket)}-${slotEndTime(endBucket)} @ ${room?.name ?? `Room#${g.roomIndex}`}`;
}

// ─── Violation Detail Builders ──────────────────────────────────────────────────

function findTimeBoundaryViolations(sessions: ClassSession[], solution: Gene[]): string[] {
    const lines: string[] = [];
    for (let i = 0; i < sessions.length; i++) {
        const endSlot = solution[i].startBucket + sessions[i].duration - 1;
        if (endSlot > 8) {
            lines.push(`  ⛔ ${sessionLabel(sessions[i])} ends at slot ${endSlot} (> 8) — exceeds day boundary`);
        }
    }
    return lines;
}

function findBreakViolations(sessions: ClassSession[], solution: Gene[]): string[] {
    const BREAK_AFTER = [2, 4];
    const lines: string[] = [];
    for (let i = 0; i < sessions.length; i++) {
        const start = solution[i].startBucket;
        const dur = sessions[i].duration;
        if (dur <= 1) continue;
        for (let s = start; s < start + dur - 1; s++) {
            if (BREAK_AFTER.includes(s)) {
                const breakType = s === 2 ? 'morning break (10:50-11:00)' : 'lunch break (13:00-14:30)';
                lines.push(`  ⛔ ${sessionLabel(sessions[i])} spans slots ${start}→${start + dur - 1}, crosses ${breakType}`);
                break;
            }
        }
    }
    return lines;
}

function findRoomOverlaps(sessions: ClassSession[], solution: Gene[], rooms: SolverInput['rooms']): string[] {
    const lines: string[] = [];
    const map = new Map<string, number[]>();
    for (let i = 0; i < sessions.length; i++) {
        const g = solution[i];
        const room = rooms[g.roomIndex];
        for (let s = g.startBucket; s < g.startBucket + sessions[i].duration; s++) {
            const key = `${room?.name ?? g.roomIndex}|${g.day}|${s}`;
            const arr = map.get(key) ?? [];
            arr.push(i);
            map.set(key, arr);
        }
    }
    for (const [key, indices] of map.entries()) {
        if (indices.length <= 1) continue;

        let lockedCount = 0;
        for (const idx of indices) {
            if (sessions[idx].isLocked) lockedCount++;
        }
        if (lockedCount === indices.length) continue; // ignore purely pre-existing

        const [roomName, dayStr, slotStr] = key.split('|');
        const labels = indices.map(i => sessionLabel(sessions[i])).join(' vs ');
        lines.push(`  ⛔ Room "${roomName}" on ${dayName(+dayStr)} slot ${slotStr} (${slotTime(+slotStr)}): ${labels}`);
    }
    return lines;
}

function findProfessorOverlaps(sessions: ClassSession[], solution: Gene[]): string[] {
    const lines: string[] = [];
    const map = new Map<string, number[]>();
    for (let i = 0; i < sessions.length; i++) {
        if (!sessions[i].professorId) continue;
        const g = solution[i];
        for (let s = g.startBucket; s < g.startBucket + sessions[i].duration; s++) {
            const key = `${sessions[i].professorId}|${g.day}|${s}`;
            const arr = map.get(key) ?? [];
            arr.push(i);
            map.set(key, arr);
        }
    }
    for (const [key, indices] of map.entries()) {
        if (indices.length <= 1) continue;

        let lockedCount = 0;
        for (const idx of indices) {
            if (sessions[idx].isLocked) lockedCount++;
        }
        if (lockedCount === indices.length) continue; // ignore purely pre-existing

        const [profId, dayStr, slotStr] = key.split('|');
        const labels = indices.map(i => sessionLabel(sessions[i])).join(' vs ');
        lines.push(`  ⛔ Professor "${profId}" on ${dayName(+dayStr)} slot ${slotStr} (${slotTime(+slotStr)}): ${labels}`);
    }
    return lines;
}

function findGroupOverlaps(sessions: ClassSession[], solution: Gene[]): string[] {
    const lines: string[] = [];
    const map = new Map<string, number[]>();
    for (let i = 0; i < sessions.length; i++) {
        const g = solution[i];
        for (let s = g.startBucket; s < g.startBucket + sessions[i].duration; s++) {
            const key = `${sessions[i].groupId}|${g.day}|${s}`;
            const arr = map.get(key) ?? [];
            arr.push(i);
            map.set(key, arr);
        }
    }
    for (const [key, indices] of map.entries()) {
        if (indices.length <= 1) continue;
        // Check if all are elective (concurrent OK) or all are locked (pre-existing OK)
        let electiveCount = 0, nonElectiveCount = 0;
        let lockedCount = 0;
        for (const idx of indices) {
            if (sessions[idx].isElective) electiveCount++;
            else nonElectiveCount++;
            if (sessions[idx].isLocked) lockedCount++;
        }
        if (nonElectiveCount === 0) continue; // all elective = concurrent, OK
        if (lockedCount === indices.length) continue; // all locked = pre-existing, ignore

        const [groupId, dayStr, slotStr] = key.split('|');
        const labels = indices.map(i => sessionLabel(sessions[i])).join(' vs ');
        lines.push(`  ⛔ Group "${groupId}" on ${dayName(+dayStr)} slot ${slotStr} (${slotTime(+slotStr)}): ${labels}`);
    }
    return lines;
}

function findWMCSectionOverlaps(sessions: ClassSession[], solution: Gene[]): string[] {
    const lines: string[] = [];
    const slotMap = new Map<string, { wmcSessions: number[]; sectionSessions: number[] }>();
    for (let i = 0; i < sessions.length; i++) {
        const g = solution[i];
        for (let s = g.startBucket; s < g.startBucket + sessions[i].duration; s++) {
            const key = `${g.day}|${s}`;
            let entry = slotMap.get(key);
            if (!entry) { entry = { wmcSessions: [], sectionSessions: [] }; slotMap.set(key, entry); }
            if (sessions[i].isWMCGroup) entry.wmcSessions.push(i);
            else entry.sectionSessions.push(i);
        }
    }
    for (const [key, { wmcSessions, sectionSessions }] of slotMap.entries()) {
        if (wmcSessions.length > 0 && sectionSessions.length > 0) {
            const allSessions = [...wmcSessions, ...sectionSessions];
            let lockedCount = 0;
            for (const idx of allSessions) {
                if (sessions[idx].isLocked) lockedCount++;
            }
            if (lockedCount === allSessions.length) continue; // ignore purely pre-existing

            const [dayStr, slotStr] = key.split('|');
            const wLabels = wmcSessions.map(i => sessionLabel(sessions[i])).join(', ');
            const sLabels = sectionSessions.map(i => sessionLabel(sessions[i])).join(', ');
            lines.push(`  ⛔ ${dayName(+dayStr)} slot ${slotStr} (${slotTime(+slotStr)}): WMC {${wLabels}} vs Section {${sLabels}}`);
        }
    }
    return lines;
}

function findHomeRoomViolations(sessions: ClassSession[], solution: Gene[], rooms: SolverInput['rooms']): string[] {
    const lines: string[] = [];
    for (let i = 0; i < sessions.length; i++) {
        if (sessions[i].slotType === 'Practical') continue;
        if (sessions[i].isElective) continue;
        if (solution[i].roomIndex !== sessions[i].homeRoomIndex) {
            const assigned = rooms[solution[i].roomIndex]?.name ?? `Room#${solution[i].roomIndex}`;
            const home = rooms[sessions[i].homeRoomIndex]?.name ?? `Room#${sessions[i].homeRoomIndex}`;
            lines.push(`  ⛔ ${sessionLabel(sessions[i])}: placed in "${assigned}" but home room is "${home}"`);
        }
    }
    return lines;
}

function findLabRoomViolations(sessions: ClassSession[], solution: Gene[], rooms: SolverInput['rooms']): string[] {
    const lines: string[] = [];
    for (let i = 0; i < sessions.length; i++) {
        if (sessions[i].slotType !== 'Practical') continue;
        const room = rooms[solution[i].roomIndex];
        if (!room || room.roomType !== 'Lab') {
            lines.push(`  ⛔ ${sessionLabel(sessions[i])}: practical in "${room?.name ?? '??'}" (type: ${room?.roomType ?? 'unknown'}) — needs Lab`);
        }
    }
    return lines;
}

// ─── Main Log Generator ────────────────────────────────────────────────────────

export function generateSolverLog(
    input: SolverInput,
    result: SolverResult,
    clusterName: string,
): string {
    const { sessions, rooms } = input;
    const { solution, fitness } = result;
    const lines: string[] = [];
    const ts = new Date().toISOString().replace(/[:.]/g, '-');

    // ─── Header ──
    lines.push('═'.repeat(80));
    lines.push(`  TIMETABLE SOLVER LOG — ${clusterName}`);
    lines.push(`  Generated: ${new Date().toLocaleString()}`);
    lines.push('═'.repeat(80));
    lines.push('');

    // ─── 1. Input Summary ──
    lines.push('┌─── INPUT SUMMARY ─────────────────────────────────────────────┐');
    const normalSessions = sessions.filter(s => !s.isLocked);
    const lockedSessions = sessions.filter(s => s.isLocked);
    lines.push(`│  Total sessions to schedule : ${normalSessions.length}`);
    lines.push(`│  Locked (published) sessions: ${lockedSessions.length}`);
    lines.push(`│  Available rooms            : ${rooms.length}`);
    lines.push(`│  Days × Slots              : ${input.numDays} × ${input.numBuckets}`);
    lines.push('│');

    // Group counts
    const groupIds = new Set(normalSessions.map(s => s.groupId));
    const subjectCodes = new Set(normalSessions.map(s => s.subjectCode));
    const electiveCount = normalSessions.filter(s => s.isElective).length;
    lines.push(`│  Unique groups             : ${groupIds.size}`);
    lines.push(`│  Unique subjects           : ${subjectCodes.size}`);
    lines.push(`│  Elective/Minor sessions   : ${electiveCount}`);
    lines.push('└──────────────────────────────────────────────────────────────┘');
    lines.push('');

    // ─── 2. Session List ──
    lines.push('┌─── ALL SESSIONS ──────────────────────────────────────────────┐');
    for (const s of sessions) {
        const g = solution[s.id];
        const placement = g ? geneLabel(g, s, rooms) : 'NOT PLACED';
        const flags = [
            s.isElective ? 'ELECTIVE' : '',
            s.isWMCGroup ? 'WMC' : '',
            s.isLocked ? 'LOCKED' : '',
        ].filter(Boolean).join(' | ');
        lines.push(`│  ${sessionLabel(s).padEnd(40)} → ${placement}${flags ? `  [${flags}]` : ''}`);
    }
    lines.push('└──────────────────────────────────────────────────────────────┘');
    lines.push('');

    // ─── 3. Solver Performance ──
    lines.push('┌─── SOLVER PERFORMANCE ────────────────────────────────────────┐');
    lines.push(`│  Algorithm          : (1+1) Evolution Strategy`);
    lines.push(`│  Max generations    : ${input.config.maxGenerations.toLocaleString()}`);
    lines.push(`│  Generations run    : ${result.totalGenerations.toLocaleString()}`);
    lines.push(`│  Best at generation : ${result.bestGeneration.toLocaleString()}`);
    lines.push(`│  Elapsed time       : ${(result.elapsedMs / 1000).toFixed(2)}s`);
    lines.push(`│  Cancelled          : ${result.cancelled ? 'Yes' : 'No'}`);
    lines.push('└──────────────────────────────────────────────────────────────┘');
    lines.push('');

    // ─── 4. Fitness Summary ──
    lines.push('┌─── FITNESS RESULT ────────────────────────────────────────────┐');
    lines.push(`│  Total fitness      : ${fitness.total}`);
    lines.push(`│  Hard violations    : ${fitness.hardViolations}`);
    lines.push(`│  Gap penalty (soft) : ${fitness.gapPenalty}`);
    lines.push(`│  FEASIBLE           : ${fitness.hardViolations === 0 ? '✅ YES' : '❌ NO'}`);
    lines.push('│');
    if (fitness.violationBreakdown) {
        const vb = fitness.violationBreakdown;
        lines.push('│  Violation Breakdown:');
        lines.push(`│    Time Boundary      : ${vb.timeBoundary}`);
        lines.push(`│    Break/Lunch Cross  : ${vb.breakCrossing}`);
        lines.push(`│    Room Overlap       : ${vb.roomOverlap}`);
        lines.push(`│    Professor Overlap  : ${vb.professorOverlap}`);
        lines.push(`│    Group Overlap      : ${vb.groupOverlap}`);
        lines.push(`│    Elective Sync      : ${vb.electiveSync}`);
        lines.push(`│    Lab Room           : ${vb.labRoom}`);
        lines.push(`│    WMC-Section Overlap: ${vb.wmcSectionOverlap}`);
        lines.push(`│    Home Room          : ${vb.homeRoom}`);
    }
    lines.push('└──────────────────────────────────────────────────────────────┘');
    lines.push('');

    // ─── 5. Detailed Violation Report ──
    if (fitness.hardViolations > 0) {
        lines.push('╔══════════════════════════════════════════════════════════════╗');
        lines.push('║  DETAILED VIOLATION REPORT                                  ║');
        lines.push('║  Each violation below explains WHY and WHERE it occurs.     ║');
        lines.push('╚══════════════════════════════════════════════════════════════╝');
        lines.push('');

        const vb = fitness.violationBreakdown!;

        if (vb.timeBoundary > 0) {
            lines.push('── Time Boundary Violations ──────────────────────────────────');
            lines.push('   WHY: A session extends beyond slot 8 (18:30). The day only has 8 slots.');
            findTimeBoundaryViolations(sessions, solution).forEach(l => lines.push(l));
            lines.push('');
        }

        if (vb.breakCrossing > 0) {
            lines.push('── Break/Lunch Crossing Violations ──────────────────────────');
            lines.push('   WHY: A multi-slot session spans across a break (10:50-11:00) or lunch (13:00-14:30).');
            findBreakViolations(sessions, solution).forEach(l => lines.push(l));
            lines.push('');
        }

        if (vb.roomOverlap > 0) {
            lines.push('── Room Overlap Violations ──────────────────────────────────');
            lines.push('   WHY: Two or more sessions are assigned to the same room at the same time.');
            findRoomOverlaps(sessions, solution, rooms).forEach(l => lines.push(l));
            lines.push('');
        }

        if (vb.professorOverlap > 0) {
            lines.push('── Professor Overlap Violations ─────────────────────────────');
            lines.push('   WHY: A professor is scheduled to teach two sessions at the same time.');
            findProfessorOverlaps(sessions, solution).forEach(l => lines.push(l));
            lines.push('');
        }

        if (vb.groupOverlap > 0) {
            lines.push('── Group (Section) Overlap Violations ───────────────────────');
            lines.push('   WHY: A student group has two non-elective sessions at the same time.');
            findGroupOverlaps(sessions, solution).forEach(l => lines.push(l));
            lines.push('');
        }

        if (vb.wmcSectionOverlap > 0) {
            lines.push('── WMC–Section Overlap Violations ───────────────────────────');
            lines.push('   WHY: A whole-batch (WMC/IT-BI) session collides with a section-level session.');
            lines.push('   All students must attend WMC, so no section class can run concurrently.');
            findWMCSectionOverlaps(sessions, solution).forEach(l => lines.push(l));
            lines.push('');
        }

        if (vb.labRoom > 0) {
            lines.push('── Lab Room Violations ──────────────────────────────────────');
            lines.push('   WHY: A Practical session is placed in a non-Lab room.');
            findLabRoomViolations(sessions, solution, rooms).forEach(l => lines.push(l));
            lines.push('');
        }

        if (vb.homeRoom > 0) {
            lines.push('── Home Room Violations ─────────────────────────────────────');
            lines.push('   WHY: A Lecture/Tutorial is not in its assigned home room.');
            findHomeRoomViolations(sessions, solution, rooms).forEach(l => lines.push(l));
            lines.push('');
        }
    } else {
        lines.push('✅ NO VIOLATIONS — Timetable is fully feasible!');
        lines.push('');
    }

    // ─── 6. Day-by-Day Schedule ──
    lines.push('┌─── DAY-BY-DAY SCHEDULE ───────────────────────────────────────┐');
    for (let d = 1; d <= 5; d++) {
        lines.push(`│`);
        lines.push(`│  ── ${dayName(d)} ${'─'.repeat(50)}`);
        const daySessions = sessions
            .map((s, i) => ({ session: s, gene: solution[i] }))
            .filter(({ gene }) => gene.day === d)
            .sort((a, b) => a.gene.startBucket - b.gene.startBucket);

        if (daySessions.length === 0) {
            lines.push(`│     (no sessions)`);
        } else {
            for (const { session, gene } of daySessions) {
                const room = rooms[gene.roomIndex];
                const endBucket = gene.startBucket + session.duration - 1;
                const time = `${slotTime(gene.startBucket)}-${slotEndTime(endBucket)}`;
                const flags = [session.isLocked ? '🔒' : '', session.isElective ? '📚' : ''].filter(Boolean).join(' ');
                lines.push(`│     ${time.padEnd(12)} ${session.subjectCode.padEnd(12)} ${session.slotType.charAt(0)} ${(room?.name ?? '??').padEnd(10)} ${flags}`);
            }
        }
    }
    lines.push('└──────────────────────────────────────────────────────────────┘');
    lines.push('');

    lines.push('═'.repeat(80));
    lines.push(`  END OF LOG — ${ts}`);
    lines.push('═'.repeat(80));

    return lines.join('\n');
}

// ─── File Download Trigger ──────────────────────────────────────────────────────

export function downloadLogFile(content: string, filename: string): void {
    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}
